    "./jobs/notify-approval"
  )
  return [
    scanBundle,
    reindexSearch,
    notifyApprovalRequested,
    notifyApprovalDecided,
  ]
}

export async function getInngestFunctions() {
  if (!_functions) _functions = loadFunctions()
  return _functions
}

